#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1005;
int n,m;
int st,ed,Fa[N],dis[N];
vector<int> g[N],e[N];
vector<int> D,ans;
bool vd[N],flag;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS_fd(int u,int fa){
    Fa[u]=fa,dis[u]=dis[fa]+1;
    for(int v:g[u])
        if(v^fa)DFS_fd(v,u);return;
}
bool DFS_can(int u,int fa){
    dis[u]=dis[fa]+1;
    if(dis[u]>2)return 0;
    if(dis[u]==2)flag=1;
    for(int v:g[u])if(v^fa&&!vd[v])
        if(!DFS_can(v,u))return 0;
    return 1;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }
    if(m>=n){cout<<"NO\n";return 0;}
    if(n==1){cout<<"YES\n1\n1\n";return 0;}
    if(n==2){cout<<"YES\n2\n1 1\n";return 0;}
    dis[0]=0,DFS_fd(1,0);
    for(int i=1;i<=n;i++)
        if(dis[i]>dis[st])st=i;
    dis[0]=0,DFS_fd(st,0);
    for(int i=1;i<=n;i++)
        if(dis[i]>dis[ed])ed=i;
    for(int i=Fa[ed];i!=st;i=Fa[i])D.pb(i),vd[i]=1;
    vd[st]=1,vd[ed]=1;
    for(int u:D)for(int v:g[u])if(!vd[v]){
        flag=0,dis[u]=0;
        if(!DFS_can(v,u)){cout<<"NO\n";return 0;}
        else if(flag)e[u].pb(v);
    }
    for(int u:D){
        ans.pb(u);
        for(int v:e[u])ans.pb(v),ans.pb(u);
    }
    cout<<"YES\n";
    cout<<ans.size()*2<<"\n";
    for(int u:ans)cout<<u<<" ";
    reverse(ans.begin(),ans.end());
    for(int u:ans)cout<<u<<" ";
    cout<<"\n";
    return 0;
}
